pub async fn get_events_after(pool: &sqlx::PgPool, created_at: &chrono::DateTime<chrono::Utc>) -> Result<Vec<GetEventsAfterRow>, sqlx::Error> {
    sqlx::query_as!(GetEventsAfterRow, "SELECT id, name, created_at FROM events WHERE created_at > $1", created_at)
        .fetch_all(pool)
        .await
}

